"""Run improved STL validator from tool library on all supplier files."""
import json
import math
import sys
from collections import defaultdict


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def parse_stl_ascii(lines):
    """Parse ASCII STL lines, return list of (declared_normal, [v1, v2, v3])."""
    triangles = []
    issues = []
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue
        i += 1
    return triangles, issues


def validate_stl(path: str) -> dict:
    """Validate an STL file and return a result dict."""
    issues = []

    # Try to detect binary vs ASCII
    with open(path, "rb") as fh:
        header = fh.read(80)
        try:
            header_str = header.decode("ascii", errors="replace").strip()
        except Exception:
            header_str = ""

    is_ascii = header_str.startswith("solid")

    if is_ascii:
        with open(path, "r", errors="replace") as fh:
            lines = fh.readlines()
        # Double check - binary files sometimes start with 'solid'
        # If we can't find 'facet normal' it's binary
        has_facet = any("facet normal" in l for l in lines[:20])
        if not has_facet:
            is_ascii = False

    if is_ascii:
        triangles, parse_issues = parse_stl_ascii(lines)
        issues.extend(parse_issues)
    else:
        # Binary STL
        import struct
        triangles = []
        with open(path, "rb") as fh:
            fh.read(80)  # header
            count_data = fh.read(4)
            if len(count_data) < 4:
                issues.append("Binary STL file too short")
                return {"valid": False, "issues": issues}
            tri_count = struct.unpack("<I", count_data)[0]
            for idx in range(tri_count):
                data = fh.read(50)
                if len(data) < 50:
                    issues.append(f"Truncated binary STL at triangle {idx}")
                    break
                nx, ny, nz = struct.unpack("<fff", data[0:12])
                v1 = struct.unpack("<fff", data[12:24])
                v2 = struct.unpack("<fff", data[24:36])
                v3 = struct.unpack("<fff", data[36:48])
                triangles.append(((nx, ny, nz), [v1, v2, v3]))

    if not triangles:
        issues.append("no_faces_found")
        return {"valid": False, "issues": issues}

    # --- Manifold check: every edge must appear exactly twice ---
    edge_count = defaultdict(int)
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] += 1

    open_edges = [e for e, cnt in edge_count.items() if cnt == 1]
    non_manifold_edges = [e for e, cnt in edge_count.items() if cnt > 2]

    if open_edges:
        issues.append(f"open_edges({len(open_edges)})")
    if non_manifold_edges:
        issues.append(f"non_manifold_edges({len(non_manifold_edges)})")

    # --- Normal consistency check (FIXED threshold: < 0 means inverted) ---
    inverted_count = 0
    degenerate_count = 0
    for declared_normal, verts in triangles:
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        mag = _magnitude(cross)
        if mag < 1e-10:
            degenerate_count += 1
            continue
        winding_normal = _normalize(cross)
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            continue  # zero normal declared, skip
        similarity = _dot(_normalize(declared_normal), winding_normal)
        # FIXED: original code used -0.99, missing most inverted normals
        # A negative dot product means normal is pointing inward (inverted)
        if similarity < 0:
            inverted_count += 1

    if degenerate_count > 0:
        issues.append(f"degenerate_triangles({degenerate_count})")
    if inverted_count > 0:
        issues.append(f"inverted_normals({inverted_count})")

    # --- Surface area ---
    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


def main():
    results = []
    for i in range(1, 21):
        fname = f"supplier_{i:03d}.stl"
        try:
            result = validate_stl(fname)
            entry = {"file": fname, "valid": result["valid"]}
            if not result["valid"]:
                # Summarize issues into a reason string
                reasons = []
                for iss in result["issues"]:
                    if iss.startswith("inverted_normals"):
                        reasons.append("inverted_normals")
                    elif iss.startswith("open_edges"):
                        reasons.append("open_edges")
                    elif iss.startswith("non_manifold_edges"):
                        reasons.append("non_manifold_edges")
                    elif iss.startswith("degenerate_triangles"):
                        reasons.append("degenerate_triangles")
                    elif iss.startswith("no_faces_found"):
                        reasons.append("no_faces_found")
                    else:
                        reasons.append(iss)
                entry["reason"] = ", ".join(reasons) if reasons else "unknown"
            results.append(entry)
            print(f"{fname}: valid={result['valid']}, issues={result['issues']}")
        except Exception as e:
            results.append({"file": fname, "valid": False, "reason": f"error: {e}"})
            print(f"{fname}: ERROR - {e}")

    with open("validation_report.json", "w") as fh:
        json.dump({"results": results}, fh, indent=2)
    print("\nReport written to validation_report.json")


if __name__ == "__main__":
    main()

